from __future__ import annotations

import hashlib
import os
from functools import lru_cache
from pathlib import Path
from typing import Optional

from PySide6.QtCore import QObject, QUrl, Signal, Qt, QByteArray
from PySide6.QtGui import QPixmap, QIcon, QPainter
from PySide6.QtNetwork import QNetworkAccessManager, QNetworkReply, QNetworkRequest
from PySide6.QtSvg import QSvgRenderer

ICONS_DIR = Path(os.environ.get('APPDATA', '')) / 'Orbit' / 'icons'
ICONS_DIR.mkdir(parents=True, exist_ok=True)


def icon_cache_path(url: str) -> Path:
    h = hashlib.md5(url.encode()).hexdigest()
    return ICONS_DIR / f'{h}.png'


def get_cached_pixmap(url: str) -> Optional[QPixmap]:
    path = icon_cache_path(url)
    if path.exists():
        px = QPixmap(str(path))
        return px if not px.isNull() else None
    return None


class IconFetcher(QObject):
    fetched = Signal(str, QPixmap)  # url, pixmap

    def __init__(self, parent=None):
        super().__init__(parent)
        self._mgr = QNetworkAccessManager(self)
        self._mgr.finished.connect(self._on_finished)
        self._pending: dict[QNetworkReply, str] = {}

    def fetch(self, url: str):
        path = icon_cache_path(url)
        if path.exists():
            px = QPixmap(str(path))
            if not px.isNull():
                self.fetched.emit(url, px)
                return
        req = QNetworkRequest(QUrl(url))
        reply = self._mgr.get(req)
        self._pending[reply] = url

    def _on_finished(self, reply: QNetworkReply):
        url = self._pending.pop(reply, None)
        if not url:
            reply.deleteLater()
            return
        if reply.error() == QNetworkReply.NetworkError.NoError:
            data = reply.readAll()
            px = QPixmap()
            px.loadFromData(data)
            if not px.isNull():
                px = px.scaled(32, 32)
                px.save(str(icon_cache_path(url)))
                self.fetched.emit(url, px)
        reply.deleteLater()


