def _make_svg(path_data: str, color: str, size: int) -> bytes:
    svg = (
        f'<svg xmlns="http://www.w3.org/2000/svg" width="{size}" height="{size}" '
        f'fill="none" viewBox="0 0 24 24" stroke="{color}" stroke-width="1.5">'
        f'{path_data}'
        f'</svg>'
    )
    return svg.encode()


@lru_cache(maxsize=256)
def icon(name: str, size: int = 16, color: str = '#c6d0f5') -> QIcon:
    """Return a QIcon for the given Heroicon name, size, and color."""
    path_data = _PATHS.get(name, _PATHS['information-circle'])
    svg_bytes = _make_svg(path_data, color, size)
    renderer = QSvgRenderer(QByteArray(svg_bytes))
    px = QPixmap(size, size)
    px.fill(Qt.transparent)
    painter = QPainter(px)
    renderer.render(painter)
    painter.end()
    return QIcon(px)


def icon_label(name: str, size: int = 16, color: str = '#c6d0f5'):
    """Return a QLabel showing the icon (useful for layouts)."""
    from PySide6.QtWidgets import QLabel
    lbl = QLabel()
    lbl.setPixmap(icon(name, size, color).pixmap(size, size))
    lbl.setFixedSize(size, size)
    return lbl
